     1→import fs from 'fs';
     2→import path from 'path';
     3→import matter from 'gray-matter';
     4→import { remark } from 'remark';
     5→import html from 'remark-html';
     6→
     7→const postsDirectory = path.join(process.cwd(), 'content', 'posts');
     8→
     9→export interface PostMeta {
    10→  slug: string;
    11→  title: string;
    12→  date: string;
    13→  excerpt: string;
    14→  published: boolean;
    15→}
    16→
    17→export interface Post extends PostMeta {
    18→  contentHtml: string;
    19→}
    20→
    21→export function getAllPostMetas(): PostMeta[] {
    22→  const fileNames = fs.readdirSync(postsDirectory);
    23→
    24→  const posts = fileNames
    25→    .filter((name) => name.endsWith('.md'))
    26→    .map((fileName) => {
    27→      const filePath = path.join(postsDirectory, fileName);
    28→      const fileContents = fs.readFileSync(filePath, 'utf8');
    29→      const { data } = matter(fileContents);
    30→
    31→      return {
    32→        slug: data.slug as string,
    33→        title: data.title as string,
    34→        date: data.date as string,
    35→        excerpt: data.excerpt as string,
    36→        published: (data.published ?? true) as boolean,
    37→      };
    38→    })
    39→    .filter((post) => post.published)
    40→    .sort((a, b) => (a.date < b.date ? 1 : -1));
    41→
    42→  return posts;
    43→}
    44→
    45→export function getAllSlugs(): string[] {
    46→  const fileNames = fs.readdirSync(postsDirectory);
    47→  return fileNames
    48→    .filter((name) => name.endsWith('.md'))
    49→    .map((fileName) => fileName.replace(/\.md$/, ''));
    50→}
    51→
    52→export function getPostBySlug(slug: string): Post | null {
    53→  // Try matching by slug frontmatter value
    54→  const fileNames = fs.readdirSync(postsDirectory);
    55→
    56→  for (const fileName of fileNames) {
    57→    if (!fileName.endsWith('.md')) continue;
    58→
    59→    const filePath = path.join(postsDirectory, fileName);
    60→    const fileContents = fs.readFileSync(filePath, 'utf8');
    61→    const { data, content } = matter(fileContents);
    62→
    63→    if (data.slug !== slug) continue;
    64→    if (!(data.published ?? true)) return null;
    65→
    66→    const processedContent = remark().use(html).processSync(content);
    67→    const contentHtml = processedContent.toString();
    68→
    69→    return {
    70→      slug: data.slug as string,
    71→      title: data.title as string,
    72→      date: data.date as string,
    73→      excerpt: data.excerpt as string,
    74→      published: true,
    75→      contentHtml,
    76→    };
    77→  }
    78→
    79→  return null;
    80→}
    81→
    82→export function formatDate(dateStr: string): string {
    83→  return new Date(dateStr + 'T00:00:00').toLocaleDateString('en-US', {
    84→    year: 'numeric',
    85→    month: 'short',
    86→  });
    87→}
